A;AACA;AACA,C;;;;;;;ACjPA;AACA,yBAAyB,mBAAO,CAAC,uDAA+D;AAChG;AACA,qBAAqB,mBAAO,CAAC,kaAAoX;AACjZ;AACA,uBAAuB,mBAAO,CAAC,uPAA4O;AAC3Q;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;AACA;;AAEA;AACA,IAAI,KAAU,GAAG;AACjB;AACA;AACA;AACA;AACA;AACA;AACA,GAAG;AACH;AACA;AACA;AACA;AACA,GAAG;AACH,CAAC;;AAED","file":"155.js","sourcesContent":["<template>\r\n    <el-dialog\r\n        @open=\"open\"\r\n        @close=\"close\"\r\n        :visible=\"showDialog\"\r\n        append-to-body\r\n        title=\"Zonas de cliente\"\r\n        v-loading=\"loading\"\r\n    >\r\n        <div style=\"margin-top:5px\" class=\" d-flex justify-content-end\">\r\n            <button\r\n                type=\"button\"\r\n                class=\"btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto\"\r\n                @click.prevent=\"clickCreate()\"\r\n            >\r\n                <i class=\"icofont-plus-circle\"></i>\r\n                <span>Nuevo</span>\r\n            </button>\r\n        </div>\r\n        <div class=\"row\" v-if=\"zones.length != 0\">\r\n            <table class=\"table table-responsive table-striped\">\r\n                <thead>\r\n                    <tr>\r\n                        <th>#</th>\r\n                        <th>Descripción</th>\r\n                        <th>Acciones</th>\r\n                    </tr>\r\n                </thead>\r\n                <tbody>\r\n                    <tr v-for=\"(zone, idx) in zones\" :key=\"idx\">\r\n                        <td>{{ idx + 1 }}</td>\r\n                        <td>{{ zone.description }}</td>\r\n                        <td>\r\n                            <button\r\n                                type=\"button\"\r\n                                :class=\"\r\n                                    `btn ${\r\n                                        zone.active\r\n                                            ? 'btn-danger'\r\n                                            : 'btn-success'\r\n                                    }`\r\n                                \"\r\n                                @click.prevent=\"clickActive(zone)\"\r\n                            >\r\n                                {{ zone.active ? \"Desactivar\" : \"Activar\" }}\r\n                            </button>\r\n                            <button\r\n                                type=\"button\"\r\n                                class=\"btn btn-primary \"\r\n                                @click.prevent=\"clickEdit(zone)\"\r\n                            >\r\n                                Editar\r\n                            </button>\r\n                            <button\r\n                                type=\"button\"\r\n                                class=\"btn btn-danger\"\r\n                                @click.prevent=\"clickDelete(zone)\"\r\n                            >\r\n                                Eliminar\r\n                            </button>\r\n                        </td>\r\n                    </tr>\r\n                </tbody>\r\n            </table>\r\n        </div>\r\n        <div v-else>\r\n            <div class=\"row\">\r\n                <div class=\"col-12\">\r\n                    <div class=\"alert alert-info\">\r\n                        No hay registros\r\n                    </div>\r\n                </div>\r\n            </div>\r\n        </div>\r\n        <el-dialog\r\n            width=\"550px\"\r\n            :visible.sync=\"showCreateForm\"\r\n            append-to-body\r\n            @close=\"showCreateForm = false\"\r\n            :title=\"form.id ? 'Editar Zona' : 'Crear Zona'\"\r\n        >\r\n            <div class=\"row m-2\">\r\n                <div class=\"col-12\">\r\n                    <label>Descripción</label>\r\n                    <el-input v-model=\"form.description\"></el-input>\r\n                </div>\r\n                <div\r\n                    style=\"margin-top:5px\"\r\n                    class=\"d-flex justify-content-center \"\r\n                >\r\n                    <button\r\n                        type=\"button\"\r\n                        class=\"btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto\"\r\n                        @click.prevent=\"submit\"\r\n                    >\r\n                        <span> {{ form.id ? \"Actualizar\" : \"Crear\" }} </span>\r\n                    </button>\r\n                </div>\r\n            </div>\r\n        </el-dialog>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport queryString from \"query-string\";\r\n\r\nexport default {\r\n    props: [\"showDialog\"],\r\n    data() {\r\n        return {\r\n            form: {},\r\n            loading: false,\r\n            zones: [],\r\n            resource: \"client_zones\",\r\n            search: {\r\n                column: null,\r\n                value: null\r\n            },\r\n            pagination: {\r\n                current_page: 1,\r\n                per_page: 20,\r\n                total: 0\r\n            },\r\n            showCreateForm: false\r\n        };\r\n    },\r\n    methods: {\r\n        async clickActive(zone) {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `/${this.resource}/active/${zone.id}`\r\n                );\r\n                this.$message.success(response.data.message);\r\n                this.showCreateForm = false;\r\n                await this.getRecords();\r\n            } catch (error) {\r\n                console.log(error);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        clickEdit(zone) {\r\n            this.form = zone;\r\n            this.showCreateForm = true;\r\n        },\r\n        async clickDelete(zone) {\r\n            try {\r\n                //create a $confirm with async/await\r\n                const confirm = await this.$confirm(\r\n                    \"¿Está seguro de eliminar este registro?\",\r\n                    \"Confirmación\",\r\n                    {\r\n                        confirmButtonText: \"Aceptar\",\r\n                        cancelButtonText: \"Cancelar\",\r\n                        type: \"warning\"\r\n                    }\r\n                );\r\n                if (confirm == \"confirm\") {\r\n                    this.loading = true;\r\n                    const response = await this.$http.delete(\r\n                        `/${this.resource}/delete/${zone.id}`\r\n                    );\r\n                    this.$message.success(response.data.message);\r\n                    this.showCreateForm = false;\r\n                    await this.getRecords();\r\n                }\r\n            } catch (error) {\r\n                console.log(error);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async submit() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.post(\r\n                    `/${this.resource}`,\r\n                    this.form\r\n                );\r\n                this.$message.success(response.data.message);\r\n                this.showCreateForm = false;\r\n                await this.getRecords();\r\n            } catch (error) {\r\n                console.log(error);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        clickCreate() {\r\n            this.form = {};\r\n            this.showCreateForm = true;\r\n        },\r\n        getQueryParameters() {\r\n            return queryString.stringify({\r\n                page: this.pagination.current_page,\r\n                ...this.search\r\n            });\r\n        },\r\n        async getRecords() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `/${this.resource}/records?${this.getQueryParameters()}`\r\n                );\r\n                if (response.status == 200) {\r\n                    this.zones = response.data;\r\n                    // this.pagination = response.data;\r\n                }\r\n            } catch (error) {\r\n                console.log(error);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async open() {\r\n            await this.getRecords();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/persons/client_zones.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      directives: [\n        {\n          name: \"loading\",\n          rawName: \"v-loading\",\n          value: _vm.loading,\n          expression: \"loading\"\n        }\n      ],\n      attrs: {\n        visible: _vm.showDialog,\n        \"append-to-body\": \"\",\n        title: \"Zonas de cliente\"\n      },\n      on: { open: _vm.open, close: _vm.close }\n    },\n    [\n      _c(\n        \"div\",\n        {\n          staticClass: \" d-flex justify-content-end\",\n          staticStyle: { \"margin-top\": \"5px\" }\n        },\n        [\n          _c(\n            \"button\",\n            {\n              staticClass:\n                \"btn btn-outline-primary btn-icon btn-icon-start w-100 w-md-auto\",\n              attrs: { type: \"button\" },\n              on: {\n                click: function($event) {\n                  $event.preventDefault()\n                  return _vm.clickCreate()\n                }\n              }\n            },\n            [\n              _c(\"i\", { staticClass: \"icofont-plus-circle\" }),\n              _vm._v(\" \"),\n              _c(\"span\", [_vm._v(\"Nuevo\")])\