form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button type=\"primary\" native-type=\"submit\" :loading=\"loading_submit\">Guardar</el-button>\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n\r\n</template>\r\n\r\n<script>\r\n\r\n    export default {\r\n        props: ['showDialog', 'recordId','external'],\r\n        data() {\r\n            return {\r\n                loading_submit: false,\r\n                titleDialog: null,\r\n                resource: 'card_brands',\r\n                errors: {},\r\n                form: {},\r\n            }\r\n        },\r\n        created() {\r\n            this.initForm()\r\n        },\r\n        methods: {\r\n            initForm() {\r\n                this.errors = {}\r\n                this.form = {\r\n                    id: null,\r\n                    description: null,\r\n                    is_update:false\r\n                }\r\n            },\r\n            create() {\r\n                this.titleDialog = (this.recordId)? 'Editar Tarjeta':'Nueva Tarjeta'\r\n                if (this.recordId) {\r\n                    this.$http.get(`/${this.resource}/record/${this.recordId}`)\r\n                        .then(response => {\r\n                            this.form = response.data\r\n                            this.form.is_update = true\r\n                        })\r\n                }\r\n            },\r\n            submit() {\r\n                this.loading_submit = true\r\n                this.$http.post(`/${this.resource}`, this.form)\r\n                    .then(response => {\r\n                        if (response.data.success) {\r\n                            this.$toast.success(response.data.message)\r\n                            if (this.external) {\r\n                                this.$eventHub.$emit('reloadDataCardBrands', response.data.id)\r\n                            } else {\r\n                                this.$eventHub.$emit('reloadData')\r\n                            }\r\n                            this.close()\r\n                        } else {\r\n                            this.$toast.error(response.data.message)\r\n                        }\r\n                    })\r\n                    .catch(error => {\r\n                        if (error.response.status === 422) {\r\n                            this.errors = error.response.data\r\n                        } else {\r\n                            console.log(error)\r\n                        }\r\n                    })\r\n                    .then(() => {\r\n                        this.loading_submit = false\r\n                    })\r\n            },\r\n            close() {\r\n                this.$emit('update:showDialog', false)\r\n                this.initForm()\r\n            },\r\n        }\r\n    }\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/card_brands/form.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      attrs: { title: _vm.titleDialog, visible: _vm.showDialog },\n      on: { close: _vm.close, open: _vm.create }\n    },\n    [\n      _c(\n        \"form\",\n        {\n          attrs: { autocomplete: \"off\" },\n          on: {\n            submit: function($event) {\n              $event.preventDefault()\n              return _vm.submit.apply(null, arguments)\n            }\n          }\n        },\n        [\n          _c(\"div\", { staticClass: \"form-body\" }, [\n            _c(\"div\", { staticClass: \"row\" }, [\n              _c(\"div\", { staticClass: \"col-md-4\" }, [\n                _c(\n                  \"div\",\n                  {\n                    staticClass: \"form-group\",\n                    class: { \"has-danger\": _vm.errors.id }\n                  },\n                  [\n                    _c(\"label\", { staticClass: \"